using UnityEngine;
using Force;
using RoboIguanaAgentRL;

namespace RoboIguanaRL {

    /// <summary>
    /// Provides Acces to experimental data about the tail of RoboIguana.
    /// </summary>
    public class TailManager: MonoBehaviour
    {
        [Header("Tail Force Point")]
        public SimpleForcePoint forcePoint;

        /// <summary>
        /// Current forces (x,y,z) generated by the tail.
        /// </summary>
        public Vector3 Force; 

        /// <summary>
        /// Cuurent energy consuption by the tail.
        /// </summary>
        public float EnergyConsumption;

        public float[] ControlParameters {get; set;}

        /// <summary>
        /// Initializes the tail.
        /// </summary>
        public void Initialize(float[] tailParameters)
        {
            ControlParameters = tailParameters;
            Reset();
        }

        /// <summary>
        /// Resets state of the tail.
        /// </summary>
        public void Reset()
        {
            Force = Vector3.zero;
            EnergyConsumption = 0f;
        }

        /// <summary>
        /// Calculates the forces generated by the tail.
        /// </summary>
        /// <param name="phase"></param>
        public void CalculateForces(float phase, float frequency, float swayAmplitude, float yawAmplitude, float phaseLag)
        {
            // return;
            Force.x = 0f;
            Force.y = 0f;
            Force.z = 0f;
        }

        /// <summary>
        /// Calculates the energy consumed by the tail.
        /// </summary>
        /// <param name="phase"></param>
        /// <param name="phaseLag"></param>
        /// <param name="swayAmplitude"></param>
        /// <param name="yawAmplitude"></param>
        public void CalculateEnergyConsuption(float phase, float frequency, float swayAmplitude, float yawAmplitude, float phaseLag)
        {
            return;
        }

        /// <summary>
        /// Sets generated forces and consumed energy according to input parameters.
        /// </summary>
        /// <param name="phase"></param>
        /// <param name="frequency"></param>
        /// <param name="swayAmplitude"></param>
        /// <param name="yawAmplitude"></param>
        /// <param name="phaseLag"></param>
        public void UpdateTail(float phase, float frequency, float swayAmplitude, float yawAmplitude, float phaseLag)
        {
            CalculateForces(phase, frequency, swayAmplitude, yawAmplitude, phaseLag);
            CalculateEnergyConsuption(phase, frequency, swayAmplitude, yawAmplitude, phaseLag);

            forcePoint.ApplyLocalForce(Force);
        }

    }
}